static void AddSampleProducesTypedInstructions()
{
    var loweredModule = LowerSample("add");
    var function = loweredModule.Functions.Single(static function => function.Name == "add_i32");
    var block = function.Blocks.Single();

    Assert(block.Instructions[0] is LoweredBinaryInstruction binary
        && binary.Operation == "add"
        && binary.Type == "i32"
        && binary.Left == "a"
        && binary.Right == "b"
        && binary.Result == "_0",
        "Expected add_i32 to start with a typed add instruction.");

    Assert(block.Instructions[1] is LoweredReturnInstruction ret
        && ret.Type == "i32"
        && ret.Value == "_0",
        "Expected add_i32 to return the add result through a typed return instruction.");
}

