static void PairI64SampleProducesTypedPointerLoad()
{
    var loweredModule = LowerSample("pair_i64");
    var function = loweredModule.Functions.Single(static function => function.Name == "second_field_i64");
    var block = function.Blocks.Single();

    Assert(function.Parameters.Count == 1
        && function.Parameters[0].Type == "ptr"
        && function.Parameters[0].Name == "pair",
        "Expected second_field_i64 to lower to a single ptr pair parameter.");

    Assert(block.Instructions[0] is LoweredGetElementPointerInstruction gep
        && gep.ElementType == "i8"
        && gep.Base == "pair"
        && gep.Index == 8,
        "Expected second_field_i64 to compute the second field through a byte-offset getelementptr over the pair pointer.");

    Assert(block.Instructions[1] is LoweredLoadInstruction load
        && load.Type == "i64"
        && load.Source == "tmp.0"
        && load.Result == "_0",
        "Expected second_field_i64 to load an i64 from the computed pointer address.");
}

