static void DivSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("div");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "div_i32");
    var panicCalls = function.Blocks
        .SelectMany(static block => block.Instructions.OfType<LoweredCallInstruction>())
        .Select(static call => call.Callee)
        .ToList();

    Assert(function.Blocks.Count == 5, $"Expected Cargo-built div_i32 to lower to five guarded blocks, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Blocks.SelectMany(static block => block.Instructions.OfType<LoweredBinaryInstruction>()).Any(static instruction => instruction.Operation == "sdiv"),
        "Expected Cargo-built div_i32 to lower the happy path through a typed signed division instruction.");
    Assert(panicCalls.Any(static callee => callee.Contains("panic_const_div_by_zero", StringComparison.Ordinal)),
        "Expected Cargo-built div_i32 to preserve the divide-by-zero panic call.");
    Assert(panicCalls.Any(static callee => callee.Contains("panic_const_div_overflow", StringComparison.Ordinal)),
        "Expected Cargo-built div_i32 to preserve the divide-overflow panic call.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "div_i32", [8, 2], llvmRoot);
    Assert(Equals(actualResult, 4), $"Expected Cargo-built div_i32 invocation to return 4, but got '{actualResult}'.");

    ExpectException<DivideByZeroException>(() => LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "div_i32", [8, 0], llvmRoot));
    ExpectException<OverflowException>(() => LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "div_i32", [int.MinValue, -1], llvmRoot));
}

static void DivU32SampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("div_u32");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
