    var function = loweredModule.Functions.Single(static function => function.Name == "merge_call_i32");
    var mergeBlock = function.Blocks.Single(static block => block.Name == "bb3");

    Assert(function.Blocks.Count == 4, $"Expected Cargo-built merge_call_i32 to keep a four-block branch merge shape, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(mergeBlock.Instructions[0] is LoweredPhiInstruction phi
        && phi.Type == "i32"
        && phi.Incoming.Count == 2
        && phi.Incoming.Any(static incoming => incoming.Value == "tmp.1" && incoming.SourceBlock == "bb1")
        && phi.Incoming.Any(static incoming => incoming.Value == "tmp.2" && incoming.SourceBlock == "bb2"),
        "Expected Cargo-built merge_call_i32 to lower the branch merge through a typed scalar phi instruction.");
    Assert(mergeBlock.Instructions.OfType<LoweredBinaryInstruction>().Any(static binary =>
            binary.Type == "i32"
            && binary.Left == "value.sroa.0.0"
            && binary.Result == "_0"),
        "Expected Cargo-built merge_call_i32 to consume the phi result in a typed binary instruction.");

    var leftResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "merge_call_i32", [0, 5], llvmRoot);
    Assert(Equals(leftResult, 12), $"Expected Cargo-built merge_call_i32 invocation with flag 0 to return 12, but got '{leftResult}'.");

    var rightResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "merge_call_i32", [1, 5], llvmRoot);
    Assert(Equals(rightResult, 14), $"Expected Cargo-built merge_call_i32 invocation with flag 1 to return 14, but got '{rightResult}'.");
}

