        "Expected Cargo-built xor_fold_vectorized to preserve vector xor operations in the vector body.");
    Assert(middleBlock.Instructions.OfType<LoweredCallInstruction>().Any(static call => call.Callee == "llvm.vector.reduce.xor.v4i32"),
        "Expected Cargo-built xor_fold_vectorized to preserve the vector xor reduction intrinsic.");

    var smallResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "xor_fold_i32", [5], llvmRoot);
    Assert(Equals(smallResult, 4), $"Expected Cargo-built xor_fold_vectorized invocation with n = 5 to return 4, but got '{smallResult}'.");

    var alignedResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "xor_fold_i32", [8], llvmRoot);
    Assert(Equals(alignedResult, 0), $"Expected Cargo-built xor_fold_vectorized invocation with n = 8 to return 0, but got '{alignedResult}'.");
}

