static void EqSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("eq");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "eq_i32");

    Assert(function.Blocks.Count == 1, $"Expected Cargo-built eq_i32 to lower to a single block after optimization, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Blocks[0].Instructions[0] is LoweredCompareInstruction compare
        && compare.Predicate == "eq"
        && compare.Type == "i32"
        && compare.Left == "a"
        && compare.Right == "b",
        "Expected Cargo-built eq_i32 to start with a typed equality compare instruction.");
    Assert(function.Blocks[0].Instructions[1] is LoweredZeroExtendInstruction zext
        && zext.FromType == "i1"
        && zext.ToType == "i32"
        && zext.Value == "_3",
        "Expected Cargo-built eq_i32 to zero-extend the i1 compare result to i32.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "eq_i32", [7, 7], llvmRoot);
    Assert(Equals(actualResult, 1), $"Expected Cargo-built eq_i32 invocation to return 1, but got '{actualResult}'.");
}

