static void DotnetRuntimeApiSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("dotnet_runtime_api");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "dotnet_runtime_score");

    var runtimeCalls = function.Blocks
        .SelectMany(static block => block.Instructions)
        .OfType<LoweredCallInstruction>()
        .Where(static call => call.Callee.StartsWith("rustlyn_dotnet_", StringComparison.Ordinal))
        .Select(static call => call.Callee)
        .ToArray();

    Assert(runtimeCalls.Length == 4,
        $"Expected Cargo-built dotnet_runtime_api to preserve four managed runtime bridge calls, but found {runtimeCalls.Length}.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_is_windows", StringComparer.Ordinal),
        "Expected Cargo-built dotnet_runtime_api to preserve the rustlyn_dotnet_is_windows bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_directory_separator_char", StringComparer.Ordinal),
        "Expected Cargo-built dotnet_runtime_api to preserve the rustlyn_dotnet_directory_separator_char bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_separator_char", StringComparer.Ordinal),
        "Expected Cargo-built dotnet_runtime_api to preserve the rustlyn_dotnet_path_separator_char bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_newline_len", StringComparer.Ordinal),
        "Expected Cargo-built dotnet_runtime_api to preserve the rustlyn_dotnet_newline_len bridge call.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "dotnet_runtime_score", [], llvmRoot);
    Assert(Equals(actualResult, 253), $"Expected Cargo-built dotnet_runtime_score invocation to return 253, but got '{actualResult}'.");
}

