static void ValidateDotnetRuntimePathStageRankSampleBuildsFromCargoManifest(
    string sampleName,
    string functionName,
    int expectedRuntimeCallCount,
    string expectedRuntimeCallCountText)
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode(sampleName);
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(function => function.Name == functionName);

    var runtimeCalls = function.Blocks
        .SelectMany(static block => block.Instructions)
        .OfType<LoweredCallInstruction>()
        .Where(static call => call.Callee.StartsWith("rustlyn_dotnet_", StringComparison.Ordinal))
        .Select(static call => call.Callee)
        .ToArray();

    Assert(runtimeCalls.Length == expectedRuntimeCallCount,
        $"Expected Cargo-built {sampleName} to preserve {expectedRuntimeCallCountText} managed runtime bridge calls, but found {runtimeCalls.Length}.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_current_directory_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_current_directory_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_copy_current_directory_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_copy_current_directory_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_temp_path_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_temp_path_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_copy_temp_path_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_copy_temp_path_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_documents_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_documents_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_copy_documents_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_copy_documents_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_full_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_full_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_full_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_full_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_root_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_root_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_root_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_root_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_relative_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_relative_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_relative_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_relative_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_directory_name_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_directory_name_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_directory_name_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_directory_name_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_combine3_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_combine3_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_combine3_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_combine3_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_file_name_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_file_name_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_file_name_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_file_name_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_change_extension_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_change_extension_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_change_extension_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_change_extension_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_get_file_name_without_extension_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_get_file_name_without_extension_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_path_copy_file_name_without_extension_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_path_copy_file_name_without_extension_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_string_replace_utf8_len", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_string_replace_utf8_len bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_string_copy_replace_utf8", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_string_copy_replace_utf8 bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_string_contains", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_string_contains bridge call.");
    Assert(runtimeCalls.Contains("rustlyn_dotnet_string_index_of", StringComparer.Ordinal),
        $"Expected Cargo-built {sampleName} to preserve the rustlyn_dotnet_string_index_of bridge call.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, functionName, [], llvmRoot);
    Assert(Equals(actualResult, 332232222), $"Expected Cargo-built {functionName} invocation to return 332232222, but got '{actualResult}'.");
}

static (string BitcodePath, string LlvmRoot) BuildCargoSampleBitcode(string sampleName)
{
    var workspaceRoot = FindWorkspaceRoot();
    if (workspaceRoot is null)
    {
        throw new InvalidOperationException("Workspace root could not be determined.");
    }

    var cratePath = Path.Combine(workspaceRoot, "samples", sampleName);
