static void AssertSingleFunctionSampleModuleSummary(string sampleName, string functionName)
{
    AssertMultiFunctionSampleModuleSummary(sampleName, functionName, [functionName], minimumFunctionCount: 1);
}

static void AssertMultiFunctionSampleModuleSummary(
    string sampleName,
    string functionName,
    IReadOnlyList<string> expectedFunctionNames,
    int minimumFunctionCount,
    IReadOnlyList<string>? expectedGlobalNames = null,
    int minimumGlobalCount = 0)
{
    var workspaceRoot = FindWorkspaceRoot();
    if (workspaceRoot is null)
    {
        throw new InvalidOperationException("Workspace root could not be determined.");
    }

    var sampleArtifactPath = Path.Combine(workspaceRoot, "artifacts", "out", sampleName, $"{sampleName}.bc");
    var llvmRoot = Path.Combine(workspaceRoot, "artifacts", "toolchains", "llvm", "clang+llvm-20.1.8-x86_64-windows");
    var llvmOptPath = Path.Combine(llvmRoot, "bin", "llvm-opt.exe");

    if (!File.Exists(sampleArtifactPath) || !File.Exists(llvmOptPath))
    {
        throw new SkipTestException($"Sample artifact or llvm-prebuilt distro is not available yet for '{sampleName}'.");
    }

    var report = BitcodeArtifactInspector.Inspect(sampleArtifactPath, llvmRoot);

    Assert(report.ModuleSummary is not null, $"Expected a module summary for the {sampleName} sample.");
    var moduleSummary = report.ModuleSummary ?? throw new InvalidOperationException($"Expected a module summary for the {sampleName} sample.");
    Assert(moduleSummary.Functions.Any(function => function.Name == functionName), $"Expected {functionName} to appear in the module summary.");
    Assert(moduleSummary.Functions.Count >= minimumFunctionCount, $"Expected at least {minimumFunctionCount.ToString(CultureInfo.InvariantCulture)} functions in the {sampleName} module summary.");
    foreach (var expectedFunctionName in expectedFunctionNames)
    {
        Assert(moduleSummary.Functions.Any(function => function.Name == expectedFunctionName), $"Expected {expectedFunctionName} to appear in the {sampleName} module summary.");
    }
    Assert(moduleSummary.Globals.Count >= minimumGlobalCount, $"Expected at least {minimumGlobalCount.ToString(CultureInfo.InvariantCulture)} globals in the {sampleName} module summary.");
    foreach (var expectedGlobalName in expectedGlobalNames ?? [])
    {
        Assert(moduleSummary.Globals.Any(global => global.Name == expectedGlobalName), $"Expected {expectedGlobalName} to appear in the {sampleName} module summary.");
    }
    Assert(moduleSummary.BasicBlockCount > 0, $"Expected at least one basic block in the {sampleName} module summary.");
    Assert(moduleSummary.InstructionCount > 0, $"Expected at least one instruction in the {sampleName} module summary.");
}

