void RunTest(string name, Action test, ICollection<string> failures)
{
    if (requestedTests is not null && !requestedTests.Contains(name))
    {
        return;
    }

    try
    {
        RunWithTimeout(test, TimeSpan.FromSeconds(30));
        Console.WriteLine($"PASS {name}");
    }
    catch (TimeoutException)
    {
        failures.Add($"{name}: TIMEOUT (30s)");
        Console.WriteLine($"TIMEOUT {name}");
    }
    catch (Exception ex)
    {
        failures.Add($"{name}: {ex.Message}");
    }
}

void RunOptionalTest(string name, Action test, ICollection<string> failures)
{
    if (requestedTests is not null && !requestedTests.Contains(name))
    {
        return;
    }

    try
    {
        RunWithTimeout(test, TimeSpan.FromSeconds(30));
        Console.WriteLine($"PASS {name}");
    }
    catch (TimeoutException)
    {
        Console.WriteLine($"TIMEOUT {name}");
    }
    catch (SkipTestException ex)
    {
        Console.WriteLine($"SKIP {name}: {ex.Message}");
    }
    catch (Exception ex)
    {
        failures.Add($"{name}: {ex.Message}");
    }
}

static void RunWithTimeout(Action action, TimeSpan timeout)
{
    Exception? caught = null;
    var thread = new Thread(() =>
    {
        try { action(); }
        catch (Exception ex) { caught = ex; }
    });
    thread.IsBackground = true;
    thread.Start();
    if (!thread.Join(timeout))
    {
        throw new TimeoutException();
    }
    if (caught is not null)
        System.Runtime.ExceptionServices.ExceptionDispatchInfo.Capture(caught).Throw();
}

static void ExpectException<TException>(Action action) where TException : Exception
{
    try
    {
        action();
    }
    catch (TargetInvocationException ex) when (ex.InnerException is TException)
    {
        return;
    }
    catch (TException)
    {
        return;
    }

    throw new InvalidOperationException($"Expected exception of type {typeof(TException).Name}.");
}

static void Assert(bool condition, string message)
{
    if (!condition)
    {
        throw new InvalidOperationException(message);
    }
}

static bool ContainsAdjacent(IReadOnlyList<string> values, string first, string second)
{
    for (var index = 0; index < values.Count - 1; index++)
    {
        if (string.Equals(values[index], first, StringComparison.Ordinal)
            && string.Equals(values[index + 1], second, StringComparison.Ordinal))
        {
            return true;
        }
    }

    return false;
}

static bool TryGetRustcSysroot(string toolchain, out string sysroot)
{
    var startInfo = new System.Diagnostics.ProcessStartInfo
    {
        FileName = "rustc",
        RedirectStandardOutput = true,
        RedirectStandardError = true,
        UseShellExecute = false,
        CreateNoWindow = true
    };
    startInfo.ArgumentList.Add($"+{toolchain}");
    startInfo.ArgumentList.Add("--print");
    startInfo.ArgumentList.Add("sysroot");

    try
    {
        using var process = System.Diagnostics.Process.Start(startInfo);
        if (process is null)
        {
            sysroot = string.Empty;
            return false;
        }

        var standardOutputTask = process.StandardOutput.ReadToEndAsync();
        var standardErrorTask = process.StandardError.ReadToEndAsync();
        process.WaitForExit();
        Task.WaitAll(standardOutputTask, standardErrorTask);

        sysroot = standardOutputTask.GetAwaiter().GetResult().Trim();
        return process.ExitCode == 0 && !string.IsNullOrWhiteSpace(sysroot);
    }
    catch
    {
        sysroot = string.Empty;
        return false;
    }
}

static string? FindWorkspaceRoot()
{
    var directory = new DirectoryInfo(Directory.GetCurrentDirectory());
    while (directory is not null)
    {
        if (Directory.Exists(Path.Combine(directory.FullName, ".git"))
            || File.Exists(Path.Combine(directory.FullName, "README.md")))
        {
            return directory.FullName;
        }

        directory = directory.Parent;
    }

    return null;
}

