static void LowererStripsTrailingMetadataFromReturnValue()
{
    var module = LoweredIrLowerer.LowerLlvmIr("""
define i32 @profile_probe_score() {
start:
  ret i32 11, !dbg !15
}
""");

    var instruction = module.Functions.Single().Blocks.Single().Instructions.Single();
        Assert(instruction is LoweredReturnInstruction, $"Expected a lowered return instruction, got {instruction.GetType().Name}.");
        var returnInstruction = (LoweredReturnInstruction)instruction;
    Assert(returnInstruction.Value == "11", $"Expected return value metadata to be stripped, got '{returnInstruction.Value}'.");
}

static void LowererStripsTrailingMetadataFromSelectValues()
{
    var module = LoweredIrLowerer.LowerLlvmIr("""
define i1 @profile_probe_select(i1 %a, i1 %b) {
start:
  %or.cond = select i1 %a, i1 true, i1 %b, !prof !9
  ret i1 %or.cond
}
""");

    var instruction = module.Functions.Single().Blocks.Single().Instructions.OfType<LoweredSelectInstruction>().Single();
    Assert(instruction.Condition == "a", $"Expected select condition metadata to be stripped, got '{instruction.Condition}'.");
    Assert(instruction.TrueValue == "true", $"Expected select true value metadata to be stripped, got '{instruction.TrueValue}'.");
    Assert(instruction.FalseValue == "b", $"Expected select false value metadata to be stripped, got '{instruction.FalseValue}'.");
}

static void LowererPreservesVtablePointerRelocations()
{
    var module = LoweredIrLowerer.LowerLlvmIr("""
@vtable.0 = private unnamed_addr constant <{ [24 x i8], ptr }> <{ [24 x i8] c"\00\00\00\00\00\00\00\00\04\00\00\00\00\00\00\00\04\00\00\00\00\00\00\00", ptr @"_ZN5probe5score17h123E" }>, align 8

define i32 @"_ZN5probe5score17h123E"(ptr %self, i32 %value) {
start:
  ret i32 %value
}
""");

    var global = module.Globals.Single();
    Assert(global.Name == "vtable.0", $"Expected vtable global name, got '{global.Name}'.");
    Assert(global.InitializerBytes.Count == 32, $"Expected vtable bytes to include the pointer slot, got {global.InitializerBytes.Count.ToString(CultureInfo.InvariantCulture)} bytes.");
    var relocation = global.PointerRelocations.Single();
    Assert(relocation.Offset == 24, $"Expected vtable function pointer relocation at offset 24, got {relocation.Offset.ToString(CultureInfo.InvariantCulture)}.");
    Assert(relocation.Target == "_ZN5probe5score17h123E", $"Expected relocation target to be normalized, got '{relocation.Target}'.");

    var descriptorModule = LoweredIrLowerer.LowerLlvmIr("""
@message = private unnamed_addr constant [5 x i8] c"hello", align 1
@fmt_piece = private unnamed_addr constant <{ ptr, [8 x i8] }> <{ ptr @message, [8 x i8] c"\05\00\00\00\00\00\00\00" }>, align 8
""");

    var descriptor = descriptorModule.Globals.Single(static global => global.Name == "fmt_piece");
    Assert(descriptor.InitializerBytes.Count == 16, $"Expected fmt descriptor to contain pointer and length bytes, got {descriptor.InitializerBytes.Count.ToString(CultureInfo.InvariantCulture)} bytes.");
    var descriptorRelocation = descriptor.PointerRelocations.Single();
    Assert(descriptorRelocation.Offset == 0, $"Expected fmt descriptor relocation at offset 0, got {descriptorRelocation.Offset.ToString(CultureInfo.InvariantCulture)}.");
    Assert(descriptorRelocation.Target == "message", $"Expected fmt descriptor relocation to target message, got '{descriptorRelocation.Target}'.");
}

static void RuntimeSplitFacadeForwardsNumericHelpers()
{
    Assert(Rustlyn.Runtime.NumericRuntime.RemEuclidI32(-5, 3) == 1, "Expected Runtime numeric rem_euclid i32 helper to match Rust semantics.");
    Assert(RuntimeBridgeHelpers.RemEuclidI32(-5, 3) == Rustlyn.Runtime.NumericRuntime.RemEuclidI32(-5, 3), "Expected Backend runtime facade to forward i32 rem_euclid.");
    Assert(Rustlyn.Runtime.NumericRuntime.RemEuclidI64(-17, 5) == 3, "Expected Runtime numeric rem_euclid i64 helper to match Rust semantics.");
    Assert(RuntimeBridgeHelpers.RemEuclidI64(-17, 5) == Rustlyn.Runtime.NumericRuntime.RemEuclidI64(-17, 5), "Expected Backend runtime facade to forward i64 rem_euclid.");
    ExpectException<DivideByZeroException>(() => Rustlyn.Runtime.NumericRuntime.RemEuclidI32(1, 0));
}

static void RuntimeSplitOwnsMemoryHelpers()
{
    var source = Marshal.AllocHGlobal(4);
    var destination = Marshal.AllocHGlobal(4);
    try
    {
        Marshal.WriteByte(source, 0, 0x10);
        Marshal.WriteByte(source, 1, 0x20);
        Marshal.WriteByte(source, 2, 0x30);
        Marshal.WriteByte(source, 3, 0x40);

        Rustlyn.Runtime.MemoryRuntime.CopyBytesI64(destination, source, 4);
        Assert(Marshal.ReadByte(destination, 0) == 0x10, "Expected Runtime memory copy helper to copy byte 0.");
        Assert(Marshal.ReadByte(destination, 3) == 0x40, "Expected Runtime memory copy helper to copy byte 3.");

        Rustlyn.Runtime.MemoryRuntime.SetBytesI64(destination, 0x7F, 4);
        Assert(Marshal.ReadByte(destination, 0) == 0x7F, "Expected Runtime memory set helper to set byte 0.");
        Assert(Marshal.ReadByte(destination, 3) == 0x7F, "Expected Runtime memory set helper to set byte 3.");
    }
    finally
    {
        Marshal.FreeHGlobal(source);
        Marshal.FreeHGlobal(destination);
    }
}

static void RuntimeSplitOwnsPanicHelpers()
{
    Rustlyn.Runtime.PanicRuntime.PreconditionCheck();
    ExpectException<DivideByZeroException>(Rustlyn.Runtime.PanicRuntime.ThrowDivideByZero);
    ExpectException<OverflowException>(Rustlyn.Runtime.PanicRuntime.ThrowOverflow);
    ExpectException<OutOfMemoryException>(Rustlyn.Runtime.PanicRuntime.ThrowOutOfMemory);
    ExpectException<InvalidOperationException>(Rustlyn.Runtime.PanicRuntime.ThrowPanic);
    ExpectException<InvalidOperationException>(Rustlyn.Runtime.PanicRuntime.ThrowUnreachable);
}

static void RuntimeSplitOwnsVectorHelpers()
{
    Assert(
        Rustlyn.Runtime.VectorRuntime.__intrinsic_fshl_i32(0x1, 0, 1) == 0x2,
        "Expected Runtime vector funnel-shift helper to preserve current i32 fshl semantics.");

    var added = Rustlyn.Runtime.VectorRuntime.__vector_i8x4_add([120, 10, -1, 3], [10, -20, 2, 4]);
    Assert(added.SequenceEqual(new sbyte[] { -126, -10, 1, 7 }), "Expected Runtime vector i8 add helper to wrap element results.");

    var max = Rustlyn.Runtime.VectorRuntime.__vector_i16x4_reduce_umax([-1, 7, -2, 1024]);
    Assert(max == -1, "Expected Runtime vector unsigned i16 reduce-max helper to compare elements as unsigned.");

    var xor = Rustlyn.Runtime.VectorRuntime.__vector_i64_reduce_xor([0x10, 0x20]);
    Assert(xor == 0x30, "Expected Runtime vector i64 reduce-xor helper to combine both lanes.");
}

static void RuntimeSplitFacadeForwardsOsHelpers()
{
    var expectedArgumentCount = Environment.GetCommandLineArgs().Length;
    Assert(Rustlyn.Os.HostEnvironment.CommandLineArgCount() == expectedArgumentCount, "Expected OS host environment helper to expose the process argument count.");
    Assert(RuntimeBridgeHelpers.CommandLineArgCount() == Rustlyn.Os.HostEnvironment.CommandLineArgCount(), "Expected Backend runtime facade to forward command-line argument count.");

    var expectedArgument = Environment.GetCommandLineArgs()[0];
    var expectedBytes = Encoding.UTF8.GetBytes(expectedArgument);
    Assert(Rustlyn.Os.HostEnvironment.Utf8CommandLineArgLength(0) == expectedBytes.Length, "Expected OS host environment helper to expose command-line argument UTF-8 byte length.");
    Assert(RuntimeBridgeHelpers.Utf8CommandLineArgLength(0) == Rustlyn.Os.HostEnvironment.Utf8CommandLineArgLength(0), "Expected Backend runtime facade to forward command-line argument UTF-8 byte length.");

    var destination = Marshal.AllocHGlobal(expectedBytes.Length);
    try
    {
        var copiedLength = RuntimeBridgeHelpers.CopyUtf8CommandLineArg(0, destination, expectedBytes.Length);
        var actualBytes = new byte[expectedBytes.Length];
        Marshal.Copy(destination, actualBytes, 0, actualBytes.Length);
        Assert(copiedLength == expectedBytes.Length, "Expected Backend runtime facade to return copied command-line argument UTF-8 byte length.");
        Assert(actualBytes.SequenceEqual(expectedBytes), "Expected Backend runtime facade to copy command-line argument UTF-8 bytes through the OS helper.");
    }
    finally
    {
        Marshal.FreeHGlobal(destination);
    }
}

static void RuntimeSplitFacadeForwardsConsoleHelpers()
{
    var originalOut = Console.Out;
    using var writer = new StringWriter(CultureInfo.InvariantCulture);
    var valuePointer = CopyUtf8TestString("hello-console", out var valueLength);
    var pathPointer = CopyUtf8TestString("sample.txt", out var pathLength);
    try
    {
        Console.SetOut(writer);

        RuntimeBridgeHelpers.ConsoleWriteLineUtf8(valuePointer, valueLength);
        RuntimeBridgeHelpers.ConsoleWritePrefixedLineUtf8(pathPointer, pathLength, 7, valuePointer, valueLength);
        RuntimeBridgeHelpers.ConsoleWritePathLineUtf8(pathPointer, pathLength, valuePointer, valueLength);
        RuntimeBridgeHelpers.ConsoleWriteNumberedLineUtf8(9, valuePointer, valueLength);
        RuntimeBridgeHelpers.ConsoleWriteI32(42);
        RuntimeBridgeHelpers.ConsoleWritePathCountUtf8(pathPointer, pathLength, 3);
    }
    finally
    {
        Console.SetOut(originalOut);
        Marshal.FreeHGlobal(valuePointer);
        Marshal.FreeHGlobal(pathPointer);
    }

    var expected = string.Join(Environment.NewLine,
        "hello-console",
        "sample.txt:7:hello-console",
        "sample.txt:hello-console",
        "9:hello-console",
        "42",
        "sample.txt:3") + Environment.NewLine;
    Assert(string.Equals(writer.ToString(), expected, StringComparison.Ordinal), "Expected Backend console facade to forward UTF-8 and numeric writes through the OS console helper.");
}

