        Assert(Rustlyn.Os.HostPath.Utf8PathCombineLengthUtf8(firstPointer, firstLength, secondPointer, secondLength) == expectedCombineBytes.Length, "Expected OS path helper to expose Path.Combine UTF-8 byte length.");
        Assert(RuntimeBridgeHelpers.Utf8PathCombineLengthUtf8(firstPointer, firstLength, secondPointer, secondLength) == Rustlyn.Os.HostPath.Utf8PathCombineLengthUtf8(firstPointer, firstLength, secondPointer, secondLength), "Expected Backend runtime facade to forward Path.Combine UTF-8 byte length.");
