static void RuntimeSplitFacadeForwardsPathResolutionHelpers()
{
    var relativePath = Path.Combine("samples", "std_fs", "fixtures", "input.txt");
    var basePath = Directory.GetCurrentDirectory();
    var relativePathPointer = CopyUtf8TestString(relativePath, out var relativePathLength);
    var basePathPointer = CopyUtf8TestString(basePath, out var basePathLength);
    try
    {
        var fullPath = Path.GetFullPath(relativePath, basePath);
        var fullPathBytes = Encoding.UTF8.GetBytes(fullPath);
        Assert(Rustlyn.Os.HostPath.Utf8PathGetFullPathLengthUtf8(relativePathPointer, relativePathLength, basePathPointer, basePathLength) == fullPathBytes.Length, "Expected OS path helper to expose Path.GetFullPath UTF-8 byte length.");
        Assert(RuntimeBridgeHelpers.Utf8PathGetFullPathLengthUtf8(relativePathPointer, relativePathLength, basePathPointer, basePathLength) == Rustlyn.Os.HostPath.Utf8PathGetFullPathLengthUtf8(relativePathPointer, relativePathLength, basePathPointer, basePathLength), "Expected Backend runtime facade to forward Path.GetFullPath UTF-8 byte length.");
        AssertPathCopy("Path.GetFullPath", fullPathBytes, destination => RuntimeBridgeHelpers.CopyUtf8PathGetFullPath(relativePathPointer, relativePathLength, basePathPointer, basePathLength, destination, fullPathBytes.Length));

        var fullPathPointer = CopyUtf8TestString(fullPath, out var fullPathLength);
        try
        {
            var root = Path.GetPathRoot(fullPath) ?? string.Empty;
            var rootBytes = Encoding.UTF8.GetBytes(root);
            Assert(Rustlyn.Os.HostPath.Utf8PathGetRootLengthUtf8(fullPathPointer, fullPathLength) == rootBytes.Length, "Expected OS path helper to expose Path.GetPathRoot UTF-8 byte length.");
            Assert(RuntimeBridgeHelpers.Utf8PathGetRootLengthUtf8(fullPathPointer, fullPathLength) == Rustlyn.Os.HostPath.Utf8PathGetRootLengthUtf8(fullPathPointer, fullPathLength), "Expected Backend runtime facade to forward Path.GetPathRoot UTF-8 byte length.");
            AssertPathCopy("Path.GetPathRoot", rootBytes, destination => RuntimeBridgeHelpers.CopyUtf8PathGetRoot(fullPathPointer, fullPathLength, destination, rootBytes.Length));

            var directoryName = Path.GetDirectoryName(fullPath) ?? string.Empty;
            var directoryNameBytes = Encoding.UTF8.GetBytes(directoryName);
            Assert(Rustlyn.Os.HostPath.Utf8PathGetDirectoryNameLengthUtf8(fullPathPointer, fullPathLength) == directoryNameBytes.Length, "Expected OS path helper to expose Path.GetDirectoryName UTF-8 byte length.");
            Assert(RuntimeBridgeHelpers.Utf8PathGetDirectoryNameLengthUtf8(fullPathPointer, fullPathLength) == Rustlyn.Os.HostPath.Utf8PathGetDirectoryNameLengthUtf8(fullPathPointer, fullPathLength), "Expected Backend runtime facade to forward Path.GetDirectoryName UTF-8 byte length.");
            AssertPathCopy("Path.GetDirectoryName", directoryNameBytes, destination => RuntimeBridgeHelpers.CopyUtf8PathGetDirectoryName(fullPathPointer, fullPathLength, destination, directoryNameBytes.Length));

            var relative = Path.GetRelativePath(basePath, fullPath);
            var relativeBytes = Encoding.UTF8.GetBytes(relative);
            Assert(Rustlyn.Os.HostPath.Utf8PathGetRelativeLengthUtf8(basePathPointer, basePathLength, fullPathPointer, fullPathLength) == relativeBytes.Length, "Expected OS path helper to expose Path.GetRelativePath UTF-8 byte length.");
            Assert(RuntimeBridgeHelpers.Utf8PathGetRelativeLengthUtf8(basePathPointer, basePathLength, fullPathPointer, fullPathLength) == Rustlyn.Os.HostPath.Utf8PathGetRelativeLengthUtf8(basePathPointer, basePathLength, fullPathPointer, fullPathLength), "Expected Backend runtime facade to forward Path.GetRelativePath UTF-8 byte length.");
            AssertPathCopy("Path.GetRelativePath", relativeBytes, destination => RuntimeBridgeHelpers.CopyUtf8PathGetRelative(basePathPointer, basePathLength, fullPathPointer, fullPathLength, destination, relativeBytes.Length));
        }
        finally
        {
            Marshal.FreeHGlobal(fullPathPointer);
        }
    }
    finally
    {
        Marshal.FreeHGlobal(relativePathPointer);
        Marshal.FreeHGlobal(basePathPointer);
    }
}

static void AssertPathCopy(string label, byte[] expectedBytes, Func<IntPtr, int> copy)
{
    var destination = Marshal.AllocHGlobal(expectedBytes.Length);
    try
    {
        var copiedLength = copy(destination);
        var actualBytes = new byte[expectedBytes.Length];
        Marshal.Copy(destination, actualBytes, 0, actualBytes.Length);
        Assert(copiedLength == expectedBytes.Length, $"Expected Backend runtime facade to return copied {label} UTF-8 byte length.");
        Assert(actualBytes.SequenceEqual(expectedBytes), $"Expected Backend runtime facade to copy {label} UTF-8 bytes through the OS path helper.");
    }
    finally
    {
        Marshal.FreeHGlobal(destination);
    }
}

static void AssertUtf8FacadeCopy(string label, string expected, Func<int> ownerLength, Func<int> facadeLength, Func<IntPtr, long, int> facadeCopy)
{
    var expectedBytes = Encoding.UTF8.GetBytes(expected);
    Assert(ownerLength() == expectedBytes.Length, $"Expected OS environment helper to expose {label} UTF-8 byte length.");
    Assert(facadeLength() == ownerLength(), $"Expected Backend runtime facade to forward {label} UTF-8 byte length.");

    var destination = Marshal.AllocHGlobal(expectedBytes.Length);
    try
    {
        var copiedLength = facadeCopy(destination, expectedBytes.Length);
        var actualBytes = new byte[expectedBytes.Length];
        Marshal.Copy(destination, actualBytes, 0, actualBytes.Length);
        Assert(copiedLength == expectedBytes.Length, $"Expected Backend runtime facade to return copied {label} UTF-8 byte length.");
        Assert(actualBytes.SequenceEqual(expectedBytes), $"Expected Backend runtime facade to copy {label} UTF-8 bytes through the OS environment helper.");
    }
    finally
    {
        Marshal.FreeHGlobal(destination);
    }
}

static IntPtr CopyUtf8TestString(string value, out int length)
{
    var bytes = Encoding.UTF8.GetBytes(value);
    length = bytes.Length;
    var pointer = Marshal.AllocHGlobal(bytes.Length);
    Marshal.Copy(bytes, 0, pointer, bytes.Length);
    return pointer;
}

static void RustBitcodeBuildStdArgumentsAvoidFakeLinker()
{
    var options = new RustBitcodeBuildOptions
    {
        Toolchain = "nightly",
        BuildStd = "std,panic_abort",
        Target = "x86_64-pc-windows-msvc"
    };

    var arguments = RustBitcodeCompiler.CreateCargoRustcArguments("Cargo.toml", options).ToArray();
    Assert(ContainsAdjacent(arguments, "-Z", "build-std=std,panic_abort"), "Expected cargo arguments to request the std build-std rung.");
    Assert(ContainsAdjacent(arguments, "--emit", "llvm-bc,llvm-ir"), "Expected cargo arguments to request LLVM bitcode plus textual IR for tool-version tolerant lowering.");
    Assert(arguments.All(static argument => !argument.Contains("rsfakelink", StringComparison.OrdinalIgnoreCase)), "Expected build-std cargo arguments to avoid the historical rsfakelink path.");
    Assert(arguments.All(static argument => !argument.Contains("linker", StringComparison.OrdinalIgnoreCase)), "Expected build-std cargo arguments to avoid linker replacement until a fixture proves it is needed.");
}

file sealed class ScannerBindableProbe
{
    public int Value => 7;

    public double Scale(float left, double right, IntPtr handle)
        => left + right + handle.ToInt64();

    public static int SumArray(int[] values)
        => values.Sum();

    public Stream OpenStream()
        => Stream.Null;
}

file sealed class ScannerUnsupportedProbe
{
    public int Supported(int value)
        => value;

    public Stream OpenStream()
        => Stream.Null;

    public int UsesStream(Stream stream)
        => stream.CanRead ? 1 : 0;

    public void RefValue(ref int value)
        => value++;

    public void OutValue(out int value)
        => value = 1;

    public T Echo<T>(T value)
        => value;

    public System.Collections.Generic.IReadOnlyList<int> ClosedGeneric()
        => Array.Empty<int>();

    public int[,] MatrixValues()
        => new int[0, 0];

    public void Callback(Action callback)
        => callback();

    public ScannerLongBackedEnum LongEnum()
        => ScannerLongBackedEnum.One;

    public int this[int index]
        => index;

    public event EventHandler Changed
    {
        add { }
        remove { }
    }
}

file enum ScannerLongBackedEnum : long
{
    One = 1
}

file enum ScannerIntBackedEnum
{
    One = 1
}

file sealed class ScannerOverloadCollisionProbe
{
    public int Collide(int value)
        => value;

    public int Collide(ScannerIntBackedEnum value)
        => (int)value;
}

file sealed class SkipTestException(string message) : Exception(message);

file sealed class TemporaryFile : IDisposable
{
    private TemporaryFile(string path)
    {
        Path = path;
    }

    public string Path { get; }

    public static TemporaryFile Create(ReadOnlySpan<byte> content)
    {
        var path = System.IO.Path.Combine(System.IO.Path.GetTempPath(), $"rustlyn-test-{Guid.NewGuid():N}.bin");
        File.WriteAllBytes(path, content.ToArray());
        return new TemporaryFile(path);
    }

    public static TemporaryFile CreateEmpty(string extension)
    {
        var path = System.IO.Path.Combine(System.IO.Path.GetTempPath(), $"rustlyn-test-{Guid.NewGuid():N}{extension}");
        return new TemporaryFile(path);
    }

    public void Dispose()
    {
        if (File.Exists(Path))
        {
            File.Delete(Path);
        }

        var runtimeConfigPath = System.IO.Path.ChangeExtension(Path, ".runtimeconfig.json");
        if (File.Exists(runtimeConfigPath))
        {
            File.Delete(runtimeConfigPath);
        }
    }
}
